int painter_partition(int boards[], int n, int k) {
    int low = 0, high = 0, result = INT_MAX;

    // Calculate low (max element) and high (sum of all elements)
    for (int i = 0; i < n; i++) {
        if (boards[i] > low) {
            low = boards[i];
        }
        high += boards[i];
    }

    while (low <= high) {
        int mid = low + (high - low) / 2;

        if (is_valid_partition(boards, n, k, mid)) {
            result = mid;
            high = mid - 1;
        } else {
